def remove_outermost_parentheses(s: str) -> str:
    if len(s) < 2 or s[0] != '(' or s[-1] != ')':
        return s

    balance = 0
    for i in range(len(s)):
        if s[i] == '(':
            balance += 1
        elif s[i] == ')':
            balance -= 1

        # If the balance becomes 0 before reaching the very end of the string,
        # it means there's an inner complete balanced parenthetical group.
        # Thus, the current s[0] and s[-1] are not the sole outermost parentheses.
        # For example, in "(A)(B)", balance becomes 0 after "(A)".
        if balance == 0 and i < len(s) - 1:
            return s

    # If the loop completes and balance is 0, it means the entire string
    # was a single balanced unit enclosed by s[0] and s[-1].
    # Examples: "((A)(B))", "(A(B)C)", "()"
    return s[1:-1]
